import type { DataChannelMessage } from "./types";

const encoder = new TextEncoder();
const decoder = new TextDecoder();

/** Encode a client action message for the data channel. */
export function encodeAction(
  action: string,
  payload: Record<string, unknown> = {},
): Uint8Array {
  const message: DataChannelMessage = {
    type: "client_action",
    action,
    payload,
  };
  return encoder.encode(JSON.stringify(message));
}

/** Decode a data channel message. Returns null if not a valid client_action. */
export function decodeMessage(data: Uint8Array): DataChannelMessage | null {
  try {
    const text = decoder.decode(data);
    const parsed = JSON.parse(text);
    if (
      parsed &&
      typeof parsed === "object" &&
      parsed.type === "client_action" &&
      typeof parsed.action === "string" &&
      parsed.action.length <= 1024
    ) {
      const payload = parsed.payload;
      const safePayload =
        typeof payload === "object" &&
        payload !== null &&
        !Array.isArray(payload)
          ? payload
          : {};
      return {
        type: "client_action",
        action: parsed.action,
        payload: safePayload as Record<string, unknown>,
      };
    }
    return null;
  } catch {
    return null;
  }
}
