import React, { useMemo, useEffect } from "react";
import { VocalBridge, type VocalBridgeOptions } from "@vocalbridgeai/sdk";
import { VocalBridgeContext } from "./context";

export interface VocalBridgeProviderProps {
  /** SDK options (auth, participantName, etc.) */
  options: VocalBridgeOptions;
  /** React children */
  children: React.ReactNode;
}

/**
 * Provides VocalBridge instance to child components.
 *
 * Usage:
 * ```tsx
 * <VocalBridgeProvider options={{ auth: { tokenUrl: "/api/voice-token" } }}>
 *   <App />
 * </VocalBridgeProvider>
 * ```
 */
export function VocalBridgeProvider({
  options,
  children,
}: VocalBridgeProviderProps) {
  const client = useMemo(() => new VocalBridge(options), []);

  // Disconnect on unmount
  useEffect(() => {
    return () => {
      client.disconnect();
    };
  }, [client]);

  const value = useMemo(() => ({ client }), [client]);

  return (
    <VocalBridgeContext.Provider value={value}>
      {children}
    </VocalBridgeContext.Provider>
  );
}
