import { useContext, useState, useEffect, useCallback, useRef } from "react";
import type { AgentAction } from "@vocalbridgeai/sdk";
import { VocalBridgeContext } from "./context";

export interface UseAgentActionsReturn {
  /** The most recent agent action received */
  lastAction: AgentAction | null;
  /** Send a custom action to the agent */
  sendAction: (
    action: string,
    payload?: Record<string, unknown>,
  ) => Promise<void>;
  /**
   * Register a handler for a specific action name.
   * Returns an unsubscribe function.
   *
   * Usage:
   * ```tsx
   * useEffect(() => {
   *   return onAction('show_product', (payload) => setProduct(payload));
   * }, [onAction]);
   * ```
   */
  onAction: (
    actionName: string,
    handler: (payload: Record<string, unknown>) => void,
  ) => () => void;
}

/**
 * Hook for bidirectional custom actions with the agent.
 */
export function useAgentActions(): UseAgentActionsReturn {
  const context = useContext(VocalBridgeContext);
  if (!context) {
    throw new Error(
      "useAgentActions must be used within a VocalBridgeProvider",
    );
  }

  const { client } = context;
  const [lastAction, setLastAction] = useState<AgentAction | null>(null);
  const handlersRef = useRef<Map<string, Set<(payload: Record<string, unknown>) => void>>>(
    new Map(),
  );

  useEffect(() => {
    const onAgentAction = (action: AgentAction) => {
      setLastAction(action);

      // Dispatch to per-action handlers
      const handlers = handlersRef.current.get(action.action);
      if (handlers) {
        for (const handler of handlers) {
          try {
            handler(action.payload);
          } catch {
            // Don't let handler errors crash
          }
        }
      }
    };

    client.on("agentAction", onAgentAction);
    return () => {
      client.off("agentAction", onAgentAction);
    };
  }, [client]);

  const sendAction = useCallback(
    async (action: string, payload?: Record<string, unknown>) => {
      await client.sendAction(action, payload);
    },
    [client],
  );

  const onAction = useCallback(
    (
      actionName: string,
      handler: (payload: Record<string, unknown>) => void,
    ): (() => void) => {
      if (!handlersRef.current.has(actionName)) {
        handlersRef.current.set(actionName, new Set());
      }
      handlersRef.current.get(actionName)!.add(handler);

      return () => {
        handlersRef.current.get(actionName)?.delete(handler);
      };
    },
    [],
  );

  return { lastAction, sendAction, onAction };
}
