import { useContext, useState, useEffect, useCallback, useRef } from "react";
import type { AIAgentQuery } from "@vocalbridgeai/sdk";
import { VocalBridgeContext } from "./context";

export interface UseAIAgentOptions {
  /**
   * Callback handler for AI agent queries.
   * When set, queries are automatically responded to with the return value.
   */
  onQuery?: (query: string) => Promise<string>;
}

export interface UseAIAgentReturn {
  /** The most recent AI agent query (null when no pending query) */
  pendingQuery: AIAgentQuery | null;
  /** Send a response to the current AI agent query */
  respond: (turnId: string, response: string) => Promise<void>;
}

/**
 * Hook for handling AI Agent integration queries.
 *
 * Automatic mode (callback):
 * ```tsx
 * useAIAgent({
 *   onQuery: async (query) => {
 *     return await myAgent.ask(query);
 *   }
 * });
 * ```
 *
 * Manual mode:
 * ```tsx
 * const { pendingQuery, respond } = useAIAgent();
 * useEffect(() => {
 *   if (pendingQuery) {
 *     myAgent.ask(pendingQuery.query).then(answer => {
 *       respond(pendingQuery.turnId, answer);
 *     });
 *   }
 * }, [pendingQuery]);
 * ```
 */
export function useAIAgent(
  options?: UseAIAgentOptions,
): UseAIAgentReturn {
  const context = useContext(VocalBridgeContext);
  if (!context) {
    throw new Error("useAIAgent must be used within a VocalBridgeProvider");
  }

  const { client } = context;
  const [pendingQuery, setPendingQuery] = useState<AIAgentQuery | null>(null);
  const onQueryRef = useRef(options?.onQuery);
  onQueryRef.current = options?.onQuery;

  // Register callback handler on the SDK if provided
  useEffect(() => {
    if (onQueryRef.current) {
      const handler = onQueryRef.current;
      const unsub = client.onAIAgentQuery(async (query) => {
        return await handler(query);
      });
      return unsub;
    }
  }, [client, options?.onQuery]);

  // Always listen for queries to update pendingQuery state
  useEffect(() => {
    const onAIQuery = (query: AIAgentQuery) => {
      setPendingQuery(query);
    };

    client.on("aiAgentQuery", onAIQuery);
    return () => {
      client.off("aiAgentQuery", onAIQuery);
    };
  }, [client]);

  const respond = useCallback(
    async (turnId: string, response: string) => {
      await client.sendAIAgentResponse(turnId, response);
      setPendingQuery(null);
    },
    [client],
  );

  return { pendingQuery, respond };
}
