import type {
  AuthConfig,
  ApiKeyAuth,
  TokenUrlAuth,
  TokenProviderAuth,
  TokenResponse,
} from "./types";
import { VocalBridgeError, VocalBridgeErrorCode } from "./errors";
import { DEFAULT_API_BASE_URL } from "./constants";

const TOKEN_FETCH_TIMEOUT_MS = 15_000;

function isApiKeyAuth(auth: AuthConfig): auth is ApiKeyAuth {
  return "apiKey" in auth;
}

function isTokenUrlAuth(auth: AuthConfig): auth is TokenUrlAuth {
  return "tokenUrl" in auth;
}

function isTokenProviderAuth(auth: AuthConfig): auth is TokenProviderAuth {
  return "tokenProvider" in auth;
}

/** Resolve auth config to a concrete token fetcher function. */
export function createTokenFetcher(
  config: AuthConfig,
  participantName: string,
  sessionId?: string,
): () => Promise<TokenResponse> {
  if (isTokenProviderAuth(config)) {
    return async () => {
      try {
        return await config.tokenProvider();
      } catch (err) {
        throw new VocalBridgeError(
          "Token provider failed",
          VocalBridgeErrorCode.TokenFetchFailed,
          err,
        );
      }
    };
  }

  if (isTokenUrlAuth(config)) {
    return async () => {
      const body: Record<string, unknown> = {
        participant_name: participantName,
        ...config.body,
      };
      if (sessionId) body.session_id = sessionId;

      try {
        const controller = new AbortController();
        const timeout = setTimeout(
          () => controller.abort(),
          TOKEN_FETCH_TIMEOUT_MS,
        );
        const response = await fetch(config.tokenUrl, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            ...config.headers,
          },
          body: JSON.stringify(body),
          signal: controller.signal,
        });
        clearTimeout(timeout);

        if (!response.ok) {
          throw await mapTokenError(response);
        }

        return (await response.json()) as TokenResponse;
      } catch (err) {
        if (err instanceof VocalBridgeError) throw err;
        throw new VocalBridgeError(
          "Failed to fetch token from URL",
          VocalBridgeErrorCode.TokenFetchFailed,
          err,
        );
      }
    };
  }

  if (isApiKeyAuth(config)) {
    if (typeof globalThis.window !== "undefined") {
      console.warn(
        "[VocalBridge] API key auth detected in a browser environment. " +
          "This exposes your API key to end users. " +
          "Use tokenUrl or tokenProvider for production.",
      );
    }
    return async () => {
      const headers: Record<string, string> = {
        "Content-Type": "application/json",
        "X-API-Key": config.apiKey,
      };
      if (config.agentId) {
        headers["X-Agent-Id"] = config.agentId;
      }

      const body: Record<string, unknown> = {
        participant_name: participantName,
      };
      if (sessionId) body.session_id = sessionId;

      try {
        const controller = new AbortController();
        const timeout = setTimeout(
          () => controller.abort(),
          TOKEN_FETCH_TIMEOUT_MS,
        );
        const response = await fetch(
          `${DEFAULT_API_BASE_URL}/api/v1/token`,
          {
            method: "POST",
            headers,
            body: JSON.stringify(body),
            signal: controller.signal,
          },
        );
        clearTimeout(timeout);

        if (!response.ok) {
          throw await mapTokenError(response);
        }

        return (await response.json()) as TokenResponse;
      } catch (err) {
        if (err instanceof VocalBridgeError) throw err;
        throw new VocalBridgeError(
          "Failed to fetch token with API key",
          VocalBridgeErrorCode.TokenFetchFailed,
          err,
        );
      }
    };
  }

  throw new VocalBridgeError(
    "Invalid auth configuration: provide apiKey, tokenUrl, or tokenProvider",
    VocalBridgeErrorCode.InvalidConfig,
  );
}

async function mapTokenError(response: Response): Promise<VocalBridgeError> {
  let detail = "";
  try {
    const body = await response.json();
    detail = body.detail || body.message || "";
  } catch {
    // Ignore parse errors
  }

  switch (response.status) {
    case 401:
      return new VocalBridgeError(
        detail || "Invalid API key",
        VocalBridgeErrorCode.TokenFetchFailed,
      );
    case 403:
      return new VocalBridgeError(
        detail || "Usage limit exceeded",
        VocalBridgeErrorCode.UsageLimitExceeded,
      );
    case 404:
      return new VocalBridgeError(
        detail || "Agent not found",
        VocalBridgeErrorCode.AgentNotFound,
      );
    default:
      return new VocalBridgeError(
        detail || `Token request failed (${response.status})`,
        VocalBridgeErrorCode.TokenFetchFailed,
      );
  }
}
