export enum VocalBridgeErrorCode {
  /** Token fetch failed (network error, 401, 403, etc.) */
  TokenFetchFailed = "TOKEN_FETCH_FAILED",
  /** Voice connection failed */
  ConnectionFailed = "CONNECTION_FAILED",
  /** Microphone access denied or unavailable */
  MicrophoneError = "MICROPHONE_ERROR",
  /** Data channel send failed */
  DataChannelError = "DATA_CHANNEL_ERROR",
  /** All reconnection attempts exhausted */
  ReconnectFailed = "RECONNECT_FAILED",
  /** Usage limit exceeded (403 from token endpoint) */
  UsageLimitExceeded = "USAGE_LIMIT_EXCEEDED",
  /** Agent not found (404 from token endpoint) */
  AgentNotFound = "AGENT_NOT_FOUND",
  /** Agent not active */
  AgentNotActive = "AGENT_NOT_ACTIVE",
  /** Invalid configuration */
  InvalidConfig = "INVALID_CONFIG",
}

export class VocalBridgeError extends Error {
  public readonly code: VocalBridgeErrorCode;
  public readonly cause?: unknown;

  constructor(
    message: string,
    code: VocalBridgeErrorCode,
    cause?: unknown,
  ) {
    super(message);
    this.name = "VocalBridgeError";
    this.code = code;
    this.cause = cause;
  }
}
