import type { VocalBridgeError } from "./errors";

// ============================================
// Auth Configuration
// ============================================

/** Direct API key auth (prototyping only — exposes key to browser) */
export interface ApiKeyAuth {
  apiKey: string;
  /** Required for account-scoped API keys */
  agentId?: string;
}

/** Token URL auth (production — your backend proxies the token request) */
export interface TokenUrlAuth {
  /** URL of your backend endpoint that returns { url, token } */
  tokenUrl: string;
  /** Optional headers to send with the token request */
  headers?: Record<string, string>;
  /** Optional body params merged into the token request */
  body?: Record<string, unknown>;
}

/** Custom token provider (maximum flexibility) */
export interface TokenProviderAuth {
  /** Async function that returns connection credentials */
  tokenProvider: () => Promise<TokenResponse>;
}

export type AuthConfig = ApiKeyAuth | TokenUrlAuth | TokenProviderAuth;

/** Response from the token endpoint */
export interface TokenResponse {
  /** Connection URL for the voice session */
  url: string;
  token: string;
  room_name: string;
  participant_identity: string;
  expires_in: number;
  agent_mode?: string;
  /** @deprecated Use `url` instead */
  livekit_url?: string;
}

// ============================================
// Connection Configuration
// ============================================

export interface VocalBridgeOptions {
  /** Authentication configuration */
  auth: AuthConfig;

  /** Participant display name (default: "User") */
  participantName?: string;

  /** Custom session ID (auto-generated if not provided) */
  sessionId?: string;

  /** Auto-acknowledge heartbeats from the agent (default: true) */
  autoAckHeartbeat?: boolean;

  /** Auto-manage agent audio playback (default: true) */
  autoPlayAudio?: boolean;

  /** Audio capture settings */
  audioCaptureDefaults?: {
    echoCancellation?: boolean;
    noiseSuppression?: boolean;
    autoGainControl?: boolean;
  };

  /** Maximum reconnection attempts (default: 3) */
  maxReconnectAttempts?: number;

  /** Reconnection delay in ms (default: 2000) */
  reconnectDelay?: number;

  /** Enable debug logging to console (default: false) */
  debug?: boolean;
}

// ============================================
// Connection State
// ============================================

export enum ConnectionState {
  /** Not connected, no connection attempt in progress */
  Disconnected = "disconnected",
  /** Fetching token / establishing connection */
  Connecting = "connecting",
  /** Connected to room, waiting for agent */
  WaitingForAgent = "waiting_for_agent",
  /** Agent has joined and is ready */
  Connected = "connected",
  /** Connection lost, attempting reconnect */
  Reconnecting = "reconnecting",
  /** Disconnecting (cleanup in progress) */
  Disconnecting = "disconnecting",
}

// ============================================
// Transcript
// ============================================

export interface TranscriptEntry {
  role: "user" | "agent";
  text: string;
  timestamp: number;
}

// ============================================
// Client Actions
// ============================================

/** Incoming action from the agent */
export interface AgentAction {
  action: string;
  payload: Record<string, unknown>;
}

/** Data channel message envelope */
export interface DataChannelMessage {
  type: "client_action";
  action: string;
  payload: Record<string, unknown>;
}

// ============================================
// AI Agent Integration
// ============================================

/** Query from the voice agent requesting an AI response */
export interface AIAgentQuery {
  query: string;
  turnId: string;
}

// ============================================
// Heartbeat
// ============================================

export interface HeartbeatPayload {
  timestamp: number;
  agent_identity: string;
}

// ============================================
// Events
// ============================================

export interface VocalBridgeEventMap {
  /** Connection state changed */
  connectionStateChanged: ConnectionState;
  /** New transcript entry (user speech or agent speech) */
  transcript: TranscriptEntry;
  /** Agent sent a custom action (excluding heartbeat and transcript) */
  agentAction: AgentAction;
  /** Heartbeat received from agent */
  heartbeat: HeartbeatPayload;
  /** AI Agent sent a query for the client to answer */
  aiAgentQuery: AIAgentQuery;
  /** Microphone mute state changed */
  microphoneChanged: boolean;
  /** Error occurred */
  error: VocalBridgeError;
}
